from ingestion.partitioning import iceberg_partition_spec

def test_day_partitions_event_time():
    spec = iceberg_partition_spec(event_time_column="created_at")
    assert {"column": "created_at", "transform": "day"} in spec

def test_buckets_high_cardinality_filter_column():
    spec = iceberg_partition_spec(event_time_column="created_at",
                                  high_cardinality_filter_column="customer_id", bucket_count=16)
    cols = {p["column"]: p["transform"] for p in spec}
    assert cols.get("created_at") == "day"
    assert cols.get("customer_id") == "bucket[16]"

