from ingestion.layout import s3_partition_path

def test_single_partition_key():
    assert s3_partition_path("s3://bronze/orders", {"dt": "2026-02-27"}) == "s3://bronze/orders/dt=2026-02-27"

def test_multi_key_ordered_and_no_double_slash():
    out = s3_partition_path("s3://bronze/orders/", {"dt": "2026-02-27", "bucket": "3"})
    assert out == "s3://bronze/orders/dt=2026-02-27/bucket=3"

