from ingestion.filesizing import target_file_count

def test_one_gib_into_128mib_files():
    assert target_file_count(1_073_741_824, 134_217_728) == 8

def test_small_batch_is_a_single_file():
    assert target_file_count(10_000_000, 134_217_728) == 1

def test_empty_batch_writes_no_files():
    assert target_file_count(0, 134_217_728) == 0
